from collections import Counter

def portfolio_summary(results: list[ScorecardResult]) -> dict:
    tier_counts = Counter(r.tier for r in results)
    avg_score = sum(r.composite_score for r in results) / len(results) if results else 0.0
    avg_by_dim: dict[str, float] = {}
    dim_keys = ["strategic_fit", "business_value", "feasibility", "risk_inverted", "cost_efficiency"]
    for k in dim_keys:
        vals = [r.dimension_scores[k] for r in results if k in r.dimension_scores]
        avg_by_dim[k] = round(sum(vals) / len(vals), 2) if vals else 0.0
    return {
        "total_requests": len(results),
        "tier_distribution": dict(tier_counts),
        "average_composite_score": round(avg_score, 2),
        "average_dimension_scores": avg_by_dim,
        "fast_track_pct": round(100 * tier_counts.get("tier1_fast_track", 0) / max(len(results), 1), 1),
    }
